"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[4307],{6238:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>h,frontMatter:()=>a,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"training/part1-foundations/notable-qa-and-discussion-highlights","title":"18. Notable Q&A and Discussion Highlights","description":"Beyond the structured instruction, Day 1 generated a rich stream of question-and-answer exchanges that captured field wisdom, product direction, and open issues. The most consequential are recorded here in thematic order, paraphrased for clarity.","source":"@site/docs/training/part1-foundations/18-notable-qa-and-discussion-highlights.md","sourceDirName":"training/part1-foundations","slug":"/training/part1-foundations/notable-qa-and-discussion-highlights","permalink":"/rsapsdocumentation/docs/training/part1-foundations/notable-qa-and-discussion-highlights","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":18,"frontMatter":{"title":"18. Notable Q&A and Discussion Highlights","sidebar_position":18},"sidebar":"docsSidebar","previous":{"title":"17. Appendix: Quick Technical Reference","permalink":"/rsapsdocumentation/docs/training/part1-foundations/appendix-quick-technical-reference"},"next":{"title":"19. Consultant Readiness Checklist (Derived from Day 1)","permalink":"/rsapsdocumentation/docs/training/part1-foundations/consultant-readiness-checklist-derived-from-day-1"}}');var i=n(4848),r=n(8453);const a={title:"18. Notable Q&A and Discussion Highlights",sidebar_position:18},o="18. Notable Q&A and Discussion Highlights",l={},d=[{value:"18.1 Product and Platform",id:"181-product-and-platform",level:2},{value:"18.2 Sessions, Clustering, and Load Balancers",id:"182-sessions-clustering-and-load-balancers",level:2},{value:"18.3 Security",id:"183-security",level:2},{value:"18.4 Federal / Classified Delivery",id:"184-federal--classified-delivery",level:2},{value:"18.5 Commercial and Engagement Strategy",id:"185-commercial-and-engagement-strategy",level:2}];function c(e){const t={h1:"h1",h2:"h2",header:"header",li:"li",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"18-notable-qa-and-discussion-highlights",children:"18. Notable Q&A and Discussion Highlights"})}),"\n",(0,i.jsx)(t.p,{children:"Beyond the structured instruction, Day 1 generated a rich stream of question-and-answer exchanges that captured field wisdom, product direction, and open issues. The most consequential are recorded here in thematic order, paraphrased for clarity."}),"\n",(0,i.jsx)(t.h2,{id:"181-product-and-platform",children:"18.1 Product and Platform"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Q: How hard is it to swap Java versions later \u2014 e.g., to a quantum-safe crypto provider in Java 24/27? A: Low effort. Java is backward compatible and PrimeKit references its runtime only through symlinks; historically the pain came from Tomcat's javax\u2192jakarta namespace migration, not the JDK. Deployments 5\u20138 years in place can be moved with a symlink repoint and validation pass."}),"\n",(0,i.jsx)(t.li,{children:"Q: Do we import users, or use an identity source? A: Both are supported. AD (or another directory) links as an identity source with a bind account \u2014 no manual creation. Populations outside AD (commonly contractors) live in the internal database and are created manually unless a directory like Entra covers them; two-identity-source deployments are routine."}),"\n",(0,i.jsx)(t.li,{children:"Q: Is there a specific order to setup scripts 1\u20134? A: Scripts 1 and 3 (local user creation and permission reset) must precede Quick Setup because Quick Setup depends on correct permissions; Script 2 (systemctl registration) is order-independent and may follow Script 4."}),"\n",(0,i.jsx)(t.li,{children:"Q: Can services be started with systemctl instead of the shell scripts? A: Yes \u2014 that is the production norm, run as the primekit local user rather than root; systemctl requires Script 2's registration. The trainer's root-based manual start was a lab-VM workaround only."}),"\n",(0,i.jsx)(t.li,{children:"Q: Is there a hard per-node connection limit (~200) before performance degrades? A: Unknown at session time; taken as an action item for the trainer to verify with engineering."}),"\n",(0,i.jsx)(t.li,{children:"Q: Word is the core product is dropping Oracle components in 9.10 \u2014 does that hit Prime? A: Plausible. The core product uses licensed Oracle JDK; a move to OpenJDK and open-source replacements would matter to Prime. Follow-up email to engineering (via Steve Small's referral) was agreed."}),"\n"]}),"\n",(0,i.jsx)(t.h2,{id:"182-sessions-clustering-and-load-balancers",children:"18.2 Sessions, Clustering, and Load Balancers"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Q: Does every node issue session tokens? A: Yes \u2014 every node issues tokens and embeds its machine ID; only the issuing node can validate its own tokens because token state is in that node's memory. Any node receiving a token it did not issue forwards it to the issuer for validation before acting."}),"\n",(0,i.jsx)(t.li,{children:"Q: When can auth clustering be skipped? A: When the load balancer provides session persistence (e.g., source-IP stickiness) \u2014 the LB then guarantees the session returns to the issuing node. Clustering exists for customers without an LB or without persistence support."}),"\n",(0,i.jsx)(t.li,{children:"Q: Are token timeouts purely a Prime setting? A: No \u2014 the LB persistence window interacts with them. If the LB forgets the session before the token expires, the LB effectively wins. Rule of thumb: LB persistence \u2265 authconfig.xml idle/lifetime timeouts."}),"\n",(0,i.jsx)(t.li,{children:"Field observation: attendees agreed the load balancer \u2014 customer-owned, separately administered, often controlled by yet another team \u2014 is the single most common source of onsite schedule slip ('we run into the load balancer and have to come back the next day')."}),"\n"]}),"\n",(0,i.jsx)(t.h2,{id:"183-security",children:"18.3 Security"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Q (Chandan): Is the rotating-password response really the most secure design, given clients commonly log API responses (passwords land in plain text in logs)? A: The risk is real and acknowledged. AMS does not log responses unless a custom flag is enabled, but client-side logging is outside RSA's control. Mitigations: prefer username+passcode where a human exists; for machine-to-machine, move to OAuth (client ID/secret or private-key JWT), now supported \u2014 standards-based and free of password-in-response semantics. Adoption is early (UPS among the first)."}),"\n",(0,i.jsx)(t.li,{children:"Q: What happens if the encrypted expiry attribute is corrupted? A: AMS can no longer decrypt it, treats the password as expired, and issues a fresh password on the next authentication \u2014 which doubles as a troubleshooting lever for stuck service accounts."}),"\n",(0,i.jsx)(t.li,{children:"Q: Direct CAS API callers \u2014 anything special? A: Yes \u2014 multi-step authentication flows require echoing the server-generated message ID across calls. AMS handles this internally, so AMS consumers never see it."}),"\n"]}),"\n",(0,i.jsx)(t.h2,{id:"184-federal--classified-delivery",children:"18.4 Federal / Classified Delivery"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Q (Jake): How do you protect self-service enrollment in a SCIF with no email, no phone, no smart card? A: Layered answers \u2014 trusted-agent out-of-band invite delivery; temporary challenge-group exclusion with automatic re-inclusion on self-enrollment; the credential provider (powerful once working, hard to implement); and the structural floor that /invite requires a time-limited, one-time entitlement plus authentication, making entitlement+password a defensible baseline subject to site policy."}),"\n",(0,i.jsx)(t.li,{children:"Q: Can anyone hit /invite without the entitlement? A: No. The entitlement must be granted (help desk or bulk invite) and is time-boxed (typically 2\u20133 days); afterward /invite refuses the user."}),"\n",(0,i.jsx)(t.li,{children:"Field pattern for restricted-environment troubleshooting: customers who cannot share screens or export logs are debugged by mirror-labbing \u2014 the consultant runs each command in his own lab on a shared screen, the customer runs the identical command on theirs, and outputs are compared verbally. Slow, but it works; log export remains the preferred path wherever policy allows."}),"\n",(0,i.jsx)(t.li,{children:"Patch turnaround: attendees credited the Prime team with day-or-two patch cycles when the customer's own engineers cannot crack an issue \u2014 the consultant burns a DVD/medium and the customer deploys \u2014 a responsiveness the core AM product cannot match."}),"\n"]}),"\n",(0,i.jsx)(t.h2,{id:"185-commercial-and-engagement-strategy",children:"18.5 Commercial and Engagement Strategy"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"On scoping the first SOCOM visit: the customer knows only SSP exists; the team's plan is to install the full suite, deliver the WPI/password-checkout primary use case flawlessly, and then walk the customer through the other components ('are you interested in this, or HTAP, or\u2026') \u2014 they own it all already; they simply don't have to use it yet."}),"\n",(0,i.jsx)(t.li,{children:"On the consultant-as-seller reality: budget cuts and retirements have severed many customer relationships on both sides; PS consultants increasingly are the expansion channel. 'You don't have to be the sales guy for Prime \u2014 they already bought it.'"}),"\n",(0,i.jsx)(t.li,{children:"On audit evidence (Christina): customers scramble every audit cycle to prove controls (password complexity, IAM controls) and settle for screenshots; pre-packaged compliance proof for RSA components would be immediately valuable and is largely an assembly exercise given existing hardening work."}),"\n"]})]})}function h(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>a,x:()=>o});var s=n(6540);const i={},r=s.createContext(i);function a(e){const t=s.useContext(r);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(r.Provider,{value:t},e.children)}}}]);